    const store=[{id:'rocket',emoji:'🚀',name:'טיל זהב',cost:80,type:'badge'},{id:'owl',emoji:'🦉',name:'חבר חכם',cost:120,type:'badge'},{id:'planet',emoji:'🪐',name:'כוכב אישי',cost:250,type:'badge'},{id:'dragon',emoji:'🐉',name:'דרקון אמיץ',cost:420,type:'badge'},{id:'castle',emoji:'🏰',name:'ארמון הידע',cost:750,type:'badge'},{id:'diamond',emoji:'💎',name:'יהלום הידע',cost:1400,type:'badge'},{id:'trophy',emoji:'🏆',name:'גביע האלופים',cost:2500,type:'badge'},{id:'galaxy',emoji:'🌌',name:'עולם הגלקסיה',cost:4000,type:'badge'}];
    function renderShop(){$('#shopItems').innerHTML=store.map(i=>`<div class="card item"><div class="emoji">${i.emoji}</div><h3>${i.name}</h3><small>פריט מיוחד לחדר</small><p>⭐ ${i.cost}</p><button class="btn ${state.owned.includes(i.id)?'success':''}" ${state.owned.includes(i.id)?'disabled':''} onclick="buy('${i.id}')">${state.owned.includes(i.id)?'בחדר שלי ✓':'רכישה'}</button></div>`).join('')}
