    function buy(id){let i=store.find(x=>x.id===id);if(!i)return;if(state.points<i.cost)return toast(`עדיין חסרות ${i.cost-state.points} נקודות לפרס הזה`);state.points-=i.cost;if(!state.owned.includes(id))state.owned.push(id);save();toast(`${i.name} הוצב במקום שלו בחדר! 🎁`)}
    function weekKey(){let d=new Date();d.setHours(12,0,0,0);d.setDate(d.getDate()-d.getDay());return localDate(d)}
    function ensureWeeklyChallenge(){let key=weekKey();if(!state.weekly||state.weekly.key!==key)state.weekly={key,progress:0,target:5,claimed:false};return state.weekly}
    function progressWeeklyTask(){let w=ensureWeeklyChallenge();if(!w.claimed)w.progress=Math.min(w.target,w.progress+1)}
    function claimWeeklyReward(){let w=ensureWeeklyChallenge();if(w.progress<w.target)return toast('עוד לא השלמת את המשימה השבועית');if(w.claimed)return toast('הפרס השבועי כבר נאסף');w.claimed=true;addPoints(200);if(!state.owned.includes('weekly-star'))state.owned.push('weekly-star');save();toast('זכית בתג שבועי נדיר וב־200 נקודות! 🌟')}
    function englishRank(){let n=state.known.length;return n>=1500?{name:'מאסטר אנגלית',icon:'👑',next:2000}:n>=700?{name:'אלוף אנגלית',icon:'🏆',next:1500}:n>=300?{name:'מומחה',icon:'🎓',next:700}:n>=100?{name:'חוקר מילים',icon:'🔎',next:300}:n>=25?{name:'מתקדם',icon:'🚀',next:100}:{name:'מתחיל',icon:'🌱',next:25}}
    function renderRankAndWeekly(){let rank=englishRank(),rankBox=$('#rankCard'),weekBox=$('#weeklyChallenge');if(rankBox)rankBox.innerHTML=`<div class="rank-icon">${rank.icon}</div><div><small>הדרגה שלי</small><h2 style="margin:3px 0">${rank.name}</h2><span>${state.known.length} מילים · הדרגה הבאה ב־${rank.next}</span></div>`;if(weekBox){let w=ensureWeeklyChallenge(),pct=Math.round(w.progress/w.target*100);weekBox.innerHTML=`<small>🌟 משימה שבועית מיוחדת</small><h3>השלימו ${w.target} משימות לימוד השבוע</h3><div class="progress"><i style="width:${pct}%"></i></div><p>${w.progress}/${w.target} · הפרס: 200 נקודות ותג נדיר</p><button class="btn" ${w.progress<w.target||w.claimed?'disabled':''} onclick="claimWeeklyReward()">${w.claimed?'הפרס נאסף ✓':'איסוף הפרס'}</button>`}}
    function toggleRoomItem(id){let p=state.room.placed.indexOf(id);p>=0?state.room.placed.splice(p,1):state.room.placed.push(id);save()}
    function renderRoom(){let box=$('#roomContent');if(!box||!state.profile)return;let placed=state.room.placed||[],ownedRoom=store.filter(x=>x.type==='room'&&state.owned.includes(x.id));box.innerHTML=`<div class="room-scene">${placed.map(id=>{let x=store.find(s=>s.id===id);return x?`<span class="room-object ${x.roomClass}">${x.emoji}</span>`:''}).join('')}<div class="room-avatar">${avatarHTML(state.profile.avatar)}</div></div><div class="card" style="margin-top:16px"><h3>הקישוטים שלי</h3><p>${ownedRoom.length?'לחצו כדי להניח בחדר או להחזיר לאוסף.':'עדיין אין קישוטים. אפשר לקנות אותם בחנות הפרסים.'}</p><div class="room-controls">${ownedRoom.map(x=>`<button class="btn ${placed.includes(x.id)?'success':'secondary'}" onclick="toggleRoomItem('${x.id}')">${x.emoji} ${x.name} ${placed.includes(x.id)?'✓':''}</button>`).join('')}<button class="btn secondary" onclick="showScreen('shop')">לחנות הפרסים</button></div></div>`}
    function renderSettings(){if(!state.profile)return;$('#settingsTime').value=state.profile.time||'19:00';$('#settingsMinutes').value=String(state.settings.minutes||10);$('#settingsStyle').value=state.settings.style||'friendly';$('#settingsSound').checked=state.settings.sound!==false;$('#settingsReminder').checked=!!state.settings.reminder;$('#notificationStatus').textContent=!('Notification'in window)?'הדפדפן אינו תומך בהתראות.':Notification.permission==='denied'?'ההתראות חסומות בהגדרות הדפדפן.':Notification.permission==='granted'?'ההרשאה להתראות פעילה.':'בעת השמירה תתבקש הרשאה להתראות.';updateInstallUI()}
    async function saveSettings(){state.profile.time=$('#settingsTime').value||'19:00';state.settings.minutes=Number($('#settingsMinutes').value);state.settings.style=$('#settingsStyle').value;state.settings.sound=$('#settingsSound').checked;state.settings.reminder=$('#settingsReminder').checked;if(state.settings.reminder&&'Notification'in window&&Notification.permission==='default'){let permission=await Notification.requestPermission();if(permission!=='granted')state.settings.reminder=false}save();toast('ההגדרות נשמרו ✓')}
    function openAvatarSettings(){avatarTarget='profile';renderAvatarChoices('profileAvatars');$('#avatarModal').classList.remove('hidden')}
    function refreshLocation(){state.shabbat=null;fetchShabbat()}
    function scheduleReminder(){if(reminderTimer)clearTimeout(reminderTimer);if(!state.profile||!state.settings.reminder||!('Notification'in window)||Notification.permission!=='granted')return;let [h,m]=(state.profile.time||'19:00').split(':').map(Number),now=new Date(),next=new Date();next.setHours(h,m,0,0);if(next<=now)next.setDate(next.getDate()+1);reminderTimer=setTimeout(()=>{if(!shabbatActive()&&!state.completed.quiz)new Notification('מתקדמים 🚀',{body:'הגיע הזמן לשיעור האנגלית ולמבחן היומי.'});scheduleReminder()},Math.min(next-now,2147483647))}
    function resetApp(){if(!confirm('האם למחוק את ההתקדמות, הנקודות והמילים של המשתמש הנוכחי?'))return;if(!confirm('האיפוס אינו ניתן לביטול. להמשיך?'))return;delete userStore[activeUserId];localStorage.setItem('mamriimUsers',JSON.stringify(userStore));let next=Object.keys(userStore)[0];if(next){localStorage.setItem('mamriimActiveUser',next);localStorage.setItem('mamriimState',JSON.stringify(userStore[next]))}else{localStorage.removeItem('mamriimActiveUser');localStorage.removeItem('mamriimState')}location.reload()}
