    function hideFitnessCoach(){$('#fitnessCoach')?.classList.add('hidden')}
    function startFitnessWorkout(event){if(event){event.preventDefault();event.stopPropagation()}try{if(new Date().getDay()===6)return toast('בשבת נחים — האימון הבא יחכה לאחר השבת');if(state.fitness.completed[today()])return renderFitness();let type=fitnessPlanForToday();if(!fitnessPlans[type])type='A';let existing=state.fitness.activeWorkout;if(existing&&existing.date===today()&&fitnessPlans[existing.type]){existing.done=Array.isArray(existing.done)?existing.done:[];existing.reps=existing.reps||{};existing.rewarded=Array.isArray(existing.rewarded)?existing.rewarded:[]}else{state.fitness.activeWorkout={date:today(),type,done:[],reps:{},rewarded:[],started:Date.now()}}persistState();renderFitnessWorkout();window.scrollTo({top:0,behavior:'smooth'});setTimeout(()=>showFitnessCoach('before'),250)}catch(error){console.error('Start fitness workout error:',error);toast('לא הצלחנו לפתוח את האימון. נסו שוב');}}window.startFitnessWorkout=startFitnessWorkout
    function fitnessDemoData(name){if(name.includes('סקוואט')||name.includes('קימה וישיבה')||name.includes('ישיבת קיר'))return{type:'squat',cue:'מתיישבים לאחור לכיוון הכיסא, שומרים גב ניטרלי וברכיים בקו כפות הרגליים.',cues:['גב ניטרלי','ברכיים בקו כפות הרגליים','תנועה איטית']};if(name.includes('שכיבות סמיכה'))return{type:'push',cue:'שומרים קו ישר מהראש עד העקבים, מכופפים מרפקים ומתקרבים בשליטה.',cues:['גוף בקו ישר','מרפקים בשליטה','ללא קשת בגב']};if(name.includes('גשר גב'))return{type:'bridge',cue:'שוכבים עם ברכיים כפופות, דוחפים דרך כפות הרגליים, עולים לקו ישר ויורדים לאט.',cues:['כפות רגליים יציבות','בטן אסופה','עלייה מבוקרת']};if(name.includes('מכרע'))return{type:'lunge',cue:'צעד קטן לאחור, מורידים את הברך האחורית ישר מטה וחוזרים דרך הרגל הקדמית.',cues:['גו זקוף','ברך קדמית יציבה','ירידה ישרה']};if(name.includes('קצות האצבעות'))return{type:'calf',cue:'עולים באיטיות על קצות האצבעות, עוצרים לרגע ויורדים בשליטה.',cues:['גוף זקוף','עצירה למעלה','ירידה איטית']};if(name.includes('עמידה על רגל'))return{type:'balance',cue:'עומדים ליד תמיכה, מרימים רגל מעט ושומרים מבט קדימה וגוף גבוה.',cues:['תמיכה קרובה','מבט קדימה','נשימה רגילה']};if(name.includes('בירד'))return{type:'bird',cue:'מעמידת שש מאריכים יד ורגל נגדית, בלי לסובב את הגוף, וחוזרים לאט.',cues:['גב שטוח','יד ורגל נגדית','ללא סיבוב']};if(name.includes('שחיין'))return{type:'swim',cue:'שוכבים על הבטן ומרימים בעדינות יד ורגל נגדית, בלי להרים את הראש.',cues:['צוואר ארוך','הרמה קטנה','תנועה נגדית']};if(name.includes('דד'))return{type:'deadbug',cue:'שוכבים על הגב, מרחיקים יד ורגל נגדית ושומרים את הגב יציב.',cues:['גב יציב','יד ורגל נגדית','נשיפה בתנועה']};if(name.includes('פלאנק'))return{type:'plank',cue:'נשענים על משטח מוגבה ושומרים קו ישר מהראש עד העקבים.',cues:['ראש בהמשך לגב','בטן אסופה','קו גוף ישר']};if(name.includes('נגיעות כתף'))return{type:'bird',cue:'מעמידת שש נוגעים בכתף הנגדית ושומרים את הגוף שקט ויציב.',cues:['ברכיים מתחת לגוף','ללא נדנוד','תנועה איטית']};return{type:'plank',cue:'שומרים את מרכז הגוף אסוף ומבצעים תנועה קטנה ואיטית.',cues:['גב יציב','בטן אסופה','נשימה רגילה']}}
    function fitnessPoses(type){const P={squat:[{h:[92,22],s:[92,40],e:[76,55],w:[65,61],p:[94,70],k:[91,94],a:[88,124],k2:[101,94],a2:[105,124]},{h:[112,42],s:[105,57],e:[83,63],w:[65,61],p:[112,83],k:[86,91],a:[73,123],k2:[122,101],a2:[128,124]}],push:[{h:[65,40],s:[78,49],e:[105,58],w:[143,67],p:[105,69],k:[132,87],a:[158,105],e2:[108,64],w2:[143,70]},{h:[83,53],s:[94,61],e:[116,62],w:[143,67],p:[119,79],k:[140,92],a:[160,105],e2:[118,69],w2:[143,72]}],bridge:[{h:[35,99],s:[53,96],e:[58,112],w:[78,114],p:[91,100],k:[121,75],a:[151,112],k2:[113,80],a2:[143,114]},{h:[35,99],s:[53,94],e:[58,112],w:[78,114],p:[92,70],k:[121,75],a:[151,112],k2:[113,79],a2:[143,114]}],lunge:[{h:[87,20],s:[88,39],e:[75,58],w:[72,78],p:[90,69],k:[84,96],a:[80,124],k2:[101,94],a2:[106,124]},{h:[91,35],s:[92,53],e:[79,68],w:[77,86],p:[94,80],k:[74,94],a:[58,122],k2:[112,103],a2:[126,122]}],calf:[{h:[91,22],s:[91,40],e:[78,58],w:[78,78],p:[92,70],k:[90,96],a:[90,124],k2:[99,96],a2:[101,124]},{h:[91,13],s:[91,31],e:[78,50],w:[78,70],p:[92,61],k:[90,87],a:[92,116],k2:[99,87],a2:[103,116]}],balance:[{h:[91,22],s:[91,40],e:[78,58],w:[78,78],p:[92,70],k:[89,96],a:[88,124],k2:[102,92],a2:[112,117]},{h:[91,22],s:[91,40],e:[78,58],w:[78,78],p:[92,70],k:[89,96],a:[88,124],k2:[114,77],a2:[129,91]}],bird:[{h:[55,58],s:[70,67],e:[70,91],w:[70,115],p:[106,72],k:[106,96],a:[106,119],e2:[84,89],w2:[84,114],k2:[122,94],a2:[122,118]},{h:[43,59],s:[65,68],e:[43,65],w:[20,62],p:[104,72],k:[129,70],a:[157,67],e2:[78,91],w2:[78,115],k2:[108,96],a2:[108,119]}],plank:[{h:[48,54],s:[66,62],e:[88,72],w:[111,82],p:[105,74],k:[132,88],a:[158,103],e2:[86,77],w2:[109,87]},{h:[51,61],s:[69,68],e:[91,75],w:[111,82],p:[108,80],k:[134,92],a:[158,103],e2:[90,80],w2:[110,87]}],deadbug:[{h:[38,104],s:[58,99],e:[58,72],w:[58,43],p:[94,101],k:[98,72],a:[98,43],e2:[74,76],w2:[79,48],k2:[112,78],a2:[125,55]},{h:[38,104],s:[58,99],e:[43,78],w:[25,56],p:[94,101],k:[119,103],a:[151,105],e2:[72,74],w2:[76,45],k2:[101,72],a2:[102,43]}],swim:[{h:[38,91],s:[58,91],e:[40,88],w:[21,85],p:[98,94],k:[128,96],a:[157,98],e2:[47,94],w2:[27,96],k2:[124,101],a2:[153,105]},{h:[38,81],s:[58,84],e:[38,72],w:[19,61],p:[98,88],k:[128,78],a:[158,68],e2:[43,88],w2:[24,91],k2:[126,94],a2:[155,98]}]};return P[type]||P.plank}
    function fitnessMan(p,cls){let L=(a,b,c,w)=>`<line x1="${a[0]}" y1="${a[1]}" x2="${b[0]}" y2="${b[1]}" stroke="${c}" stroke-width="${w}" stroke-linecap="round"/>`,mid=(a,b)=>[(a[0]+b[0])/2,(a[1]+b[1])/2],e2=p.e2||[p.e[0]+7,p.e[1]+2],w2=p.w2||[p.w[0]+7,p.w[1]+2],k2=p.k2||[p.k[0]+8,p.k[1]],a2=p.a2||[p.a[0]+9,p.a[1]];return`<g class="${cls}">${L(p.p,k2,'#263a59',13)}${L(k2,a2,'#263a59',12)}${L(p.s,e2,'#f0b38f',7)}${L(e2,w2,'#f0b38f',7)}${L(p.s,mid(p.s,e2),'#2378c9',12)}${L(p.s,p.p,'#2378c9',21)}${L(p.p,p.k,'#1e3150',13)}${L(p.k,p.a,'#1e3150',12)}${L(p.s,p.e,'#f0b38f',7)}${L(p.e,p.w,'#f0b38f',7)}${L(p.s,mid(p.s,p.e),'#2f8adc',12)}<circle cx="${p.h[0]}" cy="${p.h[1]}" r="11" fill="#f0b38f"/><path d="M${p.h[0]-10} ${p.h[1]-3} Q${p.h[0]} ${p.h[1]-14} ${p.h[0]+10} ${p.h[1]-3}" fill="#273345"/><circle cx="${p.h[0]+7}" cy="${p.h[1]}" r="1.4" fill="#273345"/><path d="M${p.a[0]-6} ${p.a[1]}h15" stroke="#fff" stroke-width="7" stroke-linecap="round"/><path d="M${a2[0]-6} ${a2[1]}h15" stroke="#fff" stroke-width="7" stroke-linecap="round"/></g>`}
    function fitnessAnimationSvg(type){let [a,b]=fitnessPoses(type),extra=type==='push'?'<rect x="164" y="20" width="6" height="115" rx="3" fill="#9bb8ad"/>':type==='squat'?'<rect x="128" y="83" width="35" height="8" rx="3" fill="#8b684c"/><rect x="151" y="90" width="6" height="40" fill="#8b684c"/>':'';return`<svg class="fitness-svg" viewBox="0 0 180 140" role="img" aria-label="הדגמת תנועה של גבר בלבוש ספורט מלא">${extra}${fitnessMan(a,'pose-a')}${fitnessMan(b,'pose-b')}</svg>`}
    const fitnessDemoDataBase=fitnessDemoData;
    fitnessDemoData=function(name){if(name.includes('שכיבות סמיכה לקיר'))return{type:'wallpush',cue:'עומדים מול קיר במרחק של צעד קטן. מניחים שתי כפות ידיים על הקיר בגובה החזה, מכופפים מרפקים ומקרבים את כל הגוף לקיר — ואז דוחפים וחוזרים.',cues:['כפות ידיים בגובה החזה','העקבים נשארים על הרצפה','כל הגוף נע כיחידה אחת'],steps:['1. ידיים על הקיר','2. מתקרבים','3. דוחפים חזרה']};return fitnessDemoDataBase(name)};
    const fitnessManBase=fitnessMan;
    fitnessMan=function(p,cls){let hat=`<g class="character-detail"><path d="M${p.h[0]-13} ${p.h[1]-8} Q${p.h[0]} ${p.h[1]-18} ${p.h[0]+13} ${p.h[1]-8} L${p.h[0]+11} ${p.h[1]-3} L${p.h[0]-11} ${p.h[1]-3}Z" fill="#817b57" stroke="#48462f" stroke-width="1"/><ellipse cx="${p.h[0]}" cy="${p.h[1]-3}" rx="16" ry="3.4" fill="#918967" stroke="#48462f" stroke-width="1"/><path d="M${p.h[0]+3} ${p.h[1]+5}q6 4 8-1q-1 9-8 9q-5-2-6-7z" fill="#3e3028"/></g>`;return fitnessManBase(p,cls).replace('</g>',hat+'</g>')};
    function wallPushAnimationSvg(){let a={h:[55,42],s:[68,55],e:[98,57],w:[142,59],p:[83,82],k:[111,103],a:[145,124],e2:[99,65],w2:[142,67],k2:[116,100],a2:[151,122]},b={h:[89,45],s:[98,58],e:[119,57],w:[142,59],p:[113,83],k:[132,103],a:[155,124],e2:[120,65],w2:[142,67],k2:[136,101],a2:[160,122]};return`<svg class="fitness-svg" viewBox="0 0 180 140" role="img" aria-label="שכיבות סמיכה לקיר: הגוף כולו מתקרב לקיר וחוזר"><defs><linearGradient id="wallG" x1="0" x2="1"><stop stop-color="#d8e9e3"/><stop offset="1" stop-color="#aecdc2"/></linearGradient></defs><rect x="157" y="8" width="16" height="124" rx="3" fill="url(#wallG)"/><path d="M157 28h16M157 53h16M157 78h16M157 103h16" stroke="#91b5a8"/><path class="wall-arrow" d="M67 20h45m0 0-9-6m9 6-9 6" fill="none" stroke="#16805f" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"/><text x="52" y="15" class="demo-step">כל הגוף נע לכיוון הקיר</text>${fitnessMan(a,'pose-a')}${fitnessMan(b,'pose-b')}<circle cx="142" cy="59" r="3" fill="#f0b38f"/><circle cx="142" cy="67" r="3" fill="#f0b38f"/></svg>`}
    const fitnessAnimationSvgBase=fitnessAnimationSvg;
    fitnessAnimationSvg=function(type){return type==='wallpush'?wallPushAnimationSvg():fitnessAnimationSvgBase(type)};
    function exerciseDemo(name,i){let d=fitnessDemoData(name);return`<div class="exercise-demo hidden" id="exerciseDemo${i}"><div class="demo-stage">${fitnessAnimationSvg(d.type)}</div><div><h3 style="margin:0 0 7px">כך מבצעים נכון</h3><p style="margin:6px 0">${d.cue}</p>${d.steps?`<ol style="margin:8px 0;padding-right:20px;font-weight:800">${d.steps.map(x=>`<li>${x}</li>`).join('')}</ol>`:''}<div class="form-cues">${d.cues.map(x=>`<span>✓ ${x}</span>`).join('')}</div><small style="display:block;margin-top:9px">הדמות מציגה תנוחת התחלה ותנוחת סיום. מבצעים ברצף חלק ובטווח נוח, ללא כאב.</small></div></div>`}
    function exerciseIllustrationData(name){if(name.includes('סקוואט לכיסא'))return{images:[['assets/exercises/chair-squat.png','סקוואט לכיסא']],title:'סקוואט לכיסא',text:'עומדים לפני הכיסא, שולחים את הגוף לאחור ויורדים בשליטה לכיוון המושב.'};if(name.includes('שכיבות סמיכה לקיר'))return{images:[['assets/exercises/wall-push-start.png','מצב התחלה'],['assets/exercises/wall-push-bend.png','כיפוף המרפקים']],title:'שכיבות סמיכה לקיר',text:'מתחילים בגוף ישר ובידיים על הקיר. מכופפים את המרפקים, מקרבים את הגוף לקיר ודוחפים חזרה.'};if(name.includes('גשר גב')&&!name.includes('בצעדה'))return{images:[['assets/exercises/back-bridge.png','הרמת הגב']],title:'גשר גב',text:'שוכבים, כפות הרגליים יציבות ומרימים את הגב באיטיות עד לקו ישר.'};if(name.includes('בירד'))return{images:[['assets/exercises/bird-dog.png','יד ורגל נגדית']],title:'בירד־דוג',text:'מעמידת שש מאריכים יד ורגל נגדית ושומרים על גב יציב.'};if(name.includes('קצות האצבעות'))return{images:[['assets/exercises/calf-raise.png','עלייה על קצות האצבעות']],title:'עלייה על קצות האצבעות',text:'נעזרים בכיסא, עולים באיטיות על קצות האצבעות ויורדים בשליטה.'};return null}
    const exerciseIllustrationDataWeekABase=exerciseIllustrationData;exerciseIllustrationData=function(name){if(name.includes('מכרע אחורי'))return{images:[['assets/exercises/lunge-start.png','מצב התחלה'],['assets/exercises/lunge-down.png','ירידה מבוקרת']],title:'מכרע אחורי בתמיכה',text:'מחזיקים בכיסא, שולחים רגל אחת לאחור ומורידים את הברך האחורית בעדינות. חוזרים לעמידה ומחליפים צד.'};if(name.includes('שכיבות סמיכה בשיפוע'))return{images:[['assets/exercises/incline-push.png','כיפוף בשיפוע']],title:'שכיבות סמיכה בשיפוע',text:'מניחים ידיים על שולחן יציב, שומרים את הגוף בקו ישר, מכופפים מרפקים ודוחפים חזרה.'};if(name.includes('שחיין'))return{images:[['assets/exercises/swimmer.png','שחיין']],title:'שחיין על הבטן',text:'שוכבים על הבטן ומרימים בעדינות יד ורגל נגדית. באפליקציה מבצעים את התרגיל על משטח יבש ונוח — לא בתוך מים.'};if(name.includes('דד'))return{images:[['assets/exercises/dead-bug.png','יד ורגל נגדית']],title:'דד־באג',text:'שוכבים על הגב, מרחיקים יד ורגל נגדית ושומרים את הגב יציב על המשטח.'};if(name.includes('ישיבת קיר'))return{images:[['assets/exercises/wall-sit-start.png','עמידה ליד הקיר'],['assets/exercises/wall-sit-down.png','ירידה לישיבה']],title:'ישיבת קיר',text:'מצמידים את הגב לקיר וגולשים מעט למטה. נשארים רק בגובה שמרגיש נוח ועולים חזרה.'};return exerciseIllustrationDataWeekABase(name)}
    const exerciseIllustrationDataWeekBBase=exerciseIllustrationData;exerciseIllustrationData=function(name){if(name.includes('קימה וישיבה'))return{images:[['assets/exercises/chair-stand.png','קימה מהכיסא']],title:'קימה וישיבה מכיסא',text:'יושבים קרוב לקצה הכיסא, מניחים את כפות הרגליים היטב על הרצפה, קמים לעמידה בשליטה ומתיישבים לאט.'};if(name.includes('נגיעות כתף'))return{images:[['assets/exercises/shoulder-taps.png','נגיעה בכתף הנגדית']],title:'נגיעות כתף בעמידת שש',text:'מעמידת שש מרימים יד אחת ונוגעים בכתף הנגדית. שומרים את הגוף יציב ומחליפים יד.'};if(name.includes('גשר גב בצעדה'))return{images:[['assets/exercises/marching-bridge.png','הרמת רגל בגשר']],title:'גשר גב בצעדה',text:'מרימים את הגב לתנוחת גשר, ואז מרימים בכל פעם רגל אחת מעט מהרצפה בלי לתת לגוף להסתובב.'};if(name.includes('פלאנק מוגבה'))return{images:[['assets/exercises/elevated-plank.png','פלאנק על שולחן']],title:'פלאנק מוגבה',text:'מניחים ידיים על שולחן יציב ושומרים קו ישר מהראש עד העקבים. נושמים כרגיל ולא מקשתים את הגב.'};if(name.includes('עמידה על רגל'))return{images:[['assets/exercises/single-leg-balance.png','עמידה בתמיכה']],title:'עמידה על רגל אחת',text:'עומדים ליד כיסא יציב, מרימים רגל אחת מעט ושומרים על שיווי משקל. מחליפים צד.'};return exerciseIllustrationDataWeekBBase(name)}
    function exerciseDemo(name,i){let d=exerciseIllustrationData(name);if(!d)return'';return`<div class="exercise-demo static-demo" id="exerciseDemo${i}"><div class="exercise-illustrations ${d.images.length>1?'two':''}">${d.images.map(x=>`<figure><img src="${x[0]}" alt="${x[1]}" loading="lazy"><figcaption>${x[1]}</figcaption></figure>`).join('')}</div><div><h3 style="margin:0 0 7px">${d.title} — כך מבצעים</h3><p style="margin:6px 0;line-height:1.7">${d.text}</p><div class="static-demo-note">איור קבוע שמציג את תנוחת התרגיל</div></div></div>`}
    function toggleExerciseDemo(){}
    function renderFitnessWorkout(){let w=state.fitness.activeWorkout;if(!w||w.date!==today())return startFitnessWorkout();w.reps=w.reps||{};let exercises=fitnessPlans[w.type],finished=w.done.length===exercises.length;let earned=(w.rewarded||[]).length*5;$('#fitnessContent').innerHTML=`<div class="section-title"><h2>אימון ${w.type} · גוף מלא</h2><button class="btn secondary" onclick="renderFitness()">שמירה ויציאה</button></div><div class="card workout-progress-banner"><div><small>התקדמות באימון</small><strong>${w.done.length} מתוך ${exercises.length} תרגילים</strong></div><div class="points-live">⭐ ${earned} נקודות באימון</div></div><div class="card safety"><b>לפני שמתחילים:</b> 3–5 דקות חימום קל — הליכה במקום, סיבובי כתפיים ותנועות נוחות. עובדים בשליטה ומשאירים 2–3 חזרות “במיכל”.</div><div class="exercise-list" style="margin-top:16px">${exercises.map((x,i)=>`<div class="card exercise ${w.done.includes(i)?'done':''}"><div class="exercise-icon">${x[0]}</div><div><h3>${x[1]}</h3><small>${x[2]} · ${fitnessPrescription(x[1])}</small><br><button class="demo-btn" id="demoBtn${i}" onclick="toggleExerciseDemo(${i})">▶ צפייה בהדגמה</button></div><button class="btn ${w.done.includes(i)?'success':''}" onclick="toggleFitnessExercise(${i})">${w.done.includes(i)?'בוצע ✓':'סיימתי'}</button>${exerciseDemo(x[1],i)}</div>`).join('')}</div><div class="workout-tools"><div class="card timer-card"><h3>טיימר מובנה</h3><div class="timer-ring" id="fitnessTimerRing"><div class="timer" id="fitnessTimer">${formatFitnessTime(fitnessSeconds)}</div></div><div class="timer-presets"><button class="btn secondary" onclick="startFitnessTimer(15)">15 שנ׳</button><button class="btn secondary" onclick="startFitnessTimer(30)">30 שנ׳</button><button class="btn secondary" onclick="startFitnessTimer(45)">45 שנ׳</button><button class="btn secondary" onclick="startFitnessTimer(60)">דקה</button></div><div class="controls"><input class="custom-time" id="customFitnessTime" type="number" min="5" max="600" value="90" aria-label="זמן מותאם בשניות"><button class="btn secondary" onclick="startCustomFitnessTimer()">זמן מותאם</button><button class="btn secondary" onclick="stopFitnessTimer()">איפוס</button></div></div><div class="card"><h3>ספירת חזרות</h3><p><small>אפשר לעדכן את מספר החזרות בכל תרגיל. הנתונים נשמרים גם כשיוצאים מהאימון.</small></p><div class="rep-grid">${exercises.map((x,i)=>`<div class="rep-row ${w.done.includes(i)?'done':''}"><span>${x[0]} ${x[1]}</span><div class="rep-controls"><button onclick="changeFitnessReps(${i},-1)" aria-label="הפחת חזרה">−</button><span class="rep-count">${w.reps[i]||0}</span><button onclick="changeFitnessReps(${i},1)" aria-label="הוסף חזרה">+</button></div></div>`).join('')}</div></div></div><button class="btn wide" style="margin-top:16px" ${finished?'':'disabled'} onclick="finishFitnessWorkout()">סיום האימון וקבלת 75 נקודות נוספות</button>`;updateFitnessTimerRing()}
    const renderFitnessWorkoutBase=renderFitnessWorkout;renderFitnessWorkout=function(){renderFitnessWorkoutBase();let list=$('#fitnessContent .exercise-list');if(list)list.insertAdjacentHTML('afterend',fitnessTermsHelp())}
    function fitnessTermsHelp(){return`<div class="card sets-help"><h3>מה זה חזרה ומה זה סט?</h3><div class="sets-help-grid"><div><b>חזרה אחת</b><br><small>ביצוע מלא אחד של התרגיל. למשל: יורדים פעם אחת בסקוואט וחוזרים לעמידה.</small></div><div><b>סט אחד</b><br><small>קבוצה של כמה חזרות ברצף. למשל: 8 חזרות, מנוחה קצרה — וזה סט אחד.</small></div></div>${state.fitness.age==='gentle'?'<p class="gentle-note">במסלול הקל מתחילים בסט אחד בלבד. אם מרגישים טוב, אפשר לעבור לשני סטים.</p>':''}</div>`}
    function toggleFitnessExercise(i){let w=state.fitness.activeWorkout;if(!w)return startFitnessWorkout();w.done=Array.isArray(w.done)?w.done:[];w.rewarded=Array.isArray(w.rewarded)?w.rewarded:[];let p=w.done.indexOf(i);if(p>=0){w.done.splice(p,1);persistState();renderFitnessWorkout();return}w.done.push(i);if(!w.rewarded.includes(i)){w.rewarded.push(i);state.fitness.points=(Number(state.fitness.points)||0)+5;award(5,'מעולה! השלמת תרגיל וקיבלת 5 נקודות ⭐')}else{persistState()}renderFitnessWorkout();setTimeout(()=>showFitnessCoach('during'),180)}
    function changeFitnessReps(i,delta){let w=state.fitness.activeWorkout;if(!w)return;w.reps=w.reps||{};w.reps[i]=Math.max(0,(Number(w.reps[i])||0)+delta);save();renderFitnessWorkout()}
    function startCustomFitnessTimer(){let input=$('#customFitnessTime'),seconds=Math.max(5,Math.min(600,Number(input?.value)||90));startFitnessTimer(seconds)}
    let fitnessTimerTotal=0;
    function updateFitnessTimerRing(){let ring=$('#fitnessTimerRing');if(!ring)return;let degree=fitnessTimerTotal?Math.max(0,Math.min(360,(fitnessSeconds/fitnessTimerTotal)*360)):0;ring.style.setProperty('--progress',degree+'deg')}
    function formatFitnessTime(s){return`${String(Math.floor(s/60)).padStart(2,'0')}:${String(s%60).padStart(2,'0')}`}
    function startFitnessTimer(seconds){clearInterval(fitnessTimerId);fitnessTimerTotal=seconds;fitnessSeconds=seconds;let el=$('#fitnessTimer');if(el)el.textContent=formatFitnessTime(fitnessSeconds);updateFitnessTimerRing();fitnessTimerId=setInterval(()=>{fitnessSeconds--;let x=$('#fitnessTimer');if(x)x.textContent=formatFitnessTime(Math.max(0,fitnessSeconds));updateFitnessTimerRing();if(fitnessSeconds<=0){clearInterval(fitnessTimerId);fitnessTimerId=null;toast('זמן המנוחה הסתיים — מוכנים לסט הבא!')}},1000)}
    function stopFitnessTimer(){clearInterval(fitnessTimerId);fitnessTimerId=null;fitnessSeconds=0;fitnessTimerTotal=0;let el=$('#fitnessTimer');if(el)el.textContent='00:00';updateFitnessTimerRing()}
    function finishFitnessWorkout(){let w=state.fitness.activeWorkout;if(!w||!fitnessPlans[w.type])return renderFitness();let need=fitnessPlans[w.type].length;if(w.done.length<need)return toast(`נשארו עוד ${need-w.done.length} תרגילים — אתם ממש קרובים!`);let minutes=Math.max(1,Math.round((Date.now()-w.started)/60000));state.fitness.completed[today()]=true;state.fitness.logs.push({date:today(),type:w.type,minutes,reps:Object.values(w.reps||{}).reduce((a,b)=>a+(Number(b)||0),0),points:100});state.fitness.activeWorkout=null;state.fitness.points=(Number(state.fitness.points)||0)+75;award(75,'איזה אלופים! האימון הושלם — קיבלתם עוד 75 נקודות 🏆');checkFitnessAchievements();recordLevelTask();progressWeeklyTask();save();stopFitnessTimer();renderFitness();setTimeout(()=>showFitnessCoach('after'),250)}
    function renderFitnessPlan(){let days=state.fitness.days.filter(d=>d!==6),names=['ראשון','שני','שלישי','רביעי','חמישי','שישי','שבת'];$('#fitnessContent').innerHTML=`<div class="section-title"><h2>התוכנית השבועית שלי</h2><button class="btn secondary" onclick="renderFitness()">חזרה להיום</button></div><div class="hero fitness-hero"><div><h1>3 אימוני גוף מלא</h1><p>${days.map(d=>names[d]).join(' · ')} · ללא ציוד · יום מנוחה בין אימונים מומלץ</p></div><div class="hero-art">📅</div></div><div class="grid">${['A','B','C'].map((t,i)=>`<div class="card"><span class="badge">${names[days.slice().sort((a,b)=>a-b)[i]]}</span><h2>אימון ${t}</h2>${fitnessPlans[t].map(x=>`<p>${x[0]} ${x[1]}<br><small>${fitnessPrescription(x[1])}</small></p>`).join('')}</div>`).join('')}</div><div class="card safety" style="margin-top:18px"><h3>למה שלוש פעמים?</h3><p>כך מקבלים תרגול קבוע של קבוצות השרירים הגדולות וזמן התאוששות בין האימונים. לילדים חשוב לשלב בנוסף משחק ותנועה יומיומית; למבוגרים מומלץ לשלב גם פעילות אירובית במהלך השבוע.</p><small><a href="https://www.who.int/news-room/fact-sheets/detail/physical-activity" target="_blank">הנחיות ארגון הבריאות העולמי</a> · <a href="https://www.cdc.gov/physical-activity-basics/guidelines/index.html" target="_blank">הנחיות CDC לפי גיל</a></small></div>`}
    const fitnessAchievementDefs=[
      {id:'fit3',icon:'🔥',name:'רצף ראשון',desc:'3 אימונים מתוכננים ברצף',reward:20,test:()=>fitnessStreak()>=3},
      {id:'fit7',icon:'⚡',name:'שבועות של התמדה',desc:'7 אימונים מתוכננים ברצף',reward:50,test:()=>fitnessStreak()>=7},
      {id:'fitWeek',icon:'📅',name:'שבוע מושלם',desc:'השלמת כל האימונים המתוכננים בשבוע',reward:50,test:()=>fitnessPerfectWeeks()>=1},
      {id:'fit3Weeks',icon:'🏆',name:'שלושה שבועות מושלמים',desc:'3 שבועות שבהם בוצעו כל האימונים',reward:150,test:()=>fitnessPerfectWeeks()>=3},
      {id:'fit10',icon:'💪',name:'מתמידים',desc:'השלמת 10 אימונים',reward:40,test:()=>state.fitness.logs.length>=10},
      {id:'fit25',icon:'🥇',name:'ספורטאי אמיתי',desc:'השלמת 25 אימונים',reward:100,test:()=>state.fitness.logs.length>=25},
      {id:'fit100',icon:'🔁',name:'100 חזרות',desc:'100 חזרות מצטברות',reward:30,test:()=>fitnessTotalReps()>=100},
      {id:'fit500',icon:'🚀',name:'500 חזרות',desc:'500 חזרות מצטברות',reward:100,test:()=>fitnessTotalReps()>=500}
    ];
    const fitnessRanks=['מתחיל','מתאמן','ספורטאי','אלוף','מאסטר','אגדה'];
    const fitnessRankNeeds=[0,80,180,320,520,800];
    function fitnessTotalReps(){return state.fitness.logs.reduce((n,x)=>n+(Number(x.reps)||0),0)}
    function dateKeyLocal(d){let y=d.getFullYear(),m=String(d.getMonth()+1).padStart(2,'0'),day=String(d.getDate()).padStart(2,'0');return `${y}-${m}-${day}`}
    function fitnessStreak(){let completed=state.fitness.completed||{},days=(state.fitness.days||[]).filter(x=>x!==6),d=new Date(),count=0,started=false;for(let i=0;i<370;i++){let dow=d.getDay(),key=dateKeyLocal(d);if(dow!==6&&days.includes(dow)){if(completed[key]){count++;started=true}else if(started||key!==today())break}d.setDate(d.getDate()-1)}return count}
    function fitnessPerfectWeeks(){let logs=state.fitness.completed||{},days=(state.fitness.days||[]).filter(x=>x!==6),weeks=0;for(let w=0;w<20;w++){let d=new Date();d.setDate(d.getDate()-d.getDay()-w*7);if(days.every(day=>{let x=new Date(d);x.setDate(d.getDate()+day);return !!logs[dateKeyLocal(x)]}))weeks++}return weeks}
    function fitnessLevel(){let p=Number(state.fitness.points)||0,l=1;for(let i=1;i<fitnessRankNeeds.length;i++)if(p>=fitnessRankNeeds[i])l=i+1;return l}
    function checkFitnessAchievements(){let changed=false;fitnessAchievementDefs.forEach(a=>{if(!state.fitness.achievements.includes(a.id)&&a.test()){state.fitness.achievements.push(a.id);state.fitness.points+=a.reward;state.points+=a.reward;changed=true;toast(`הישג חדש: ${a.name} — ${a.reward} נקודות!`)}});if(changed)persistState()}
    function fitnessWeekHtml(){let names=['ראשון','שני','שלישי','רביעי','חמישי','שישי','שבת'],start=new Date();start.setDate(start.getDate()-start.getDay());return names.map((n,i)=>{let d=new Date(start);d.setDate(start.getDate()+i);let done=!!state.fitness.completed[dateKeyLocal(d)],rest=i===6||!state.fitness.days.includes(i);return `<div class="weekly-check ${done?'done':rest?'rest':''}">${done?'✓ ':rest?'☕ ':''}${n}</div>`}).join('')}
    function renderFitnessProgress(){checkFitnessAchievements();let logs=state.fitness.logs,total=logs.length,mins=logs.reduce((s,x)=>s+x.minutes,0),streak=fitnessStreak(),reps=fitnessTotalReps(),lvl=fitnessLevel(),current=fitnessRankNeeds[lvl-1],next=fitnessRankNeeds[lvl]||current,maxed=lvl>=fitnessRanks.length,pct=maxed?100:Math.max(0,Math.min(100,(state.fitness.points-current)/(next-current)*100));$('#fitnessContent').innerHTML=`<div class="section-title"><h2>התקדמות והישגים בכושר</h2><button class="btn secondary" onclick="renderFitness()">חזרה להיום</button></div><div class="card fitness-rank-card"><small>הדרגה שלי בכושר</small><h1>דרגה ${lvl} · ${fitnessRanks[lvl-1]}</h1><div class="progress"><i style="width:${pct}%"></i></div><p>${maxed?'הגעת לדרגה הגבוהה ביותר!':`${state.fitness.points} מתוך ${next} נקודות לדרגה הבאה`}</p><small>כל אימון והישג מקדמים אותך לדרגה הבאה</small></div><div class="grid"><div class="card"><h3>אימונים</h3><div class="fitness-stat">${total}</div></div><div class="card"><h3>רצף אימונים</h3><div class="fitness-stat">${streak} 🔥</div></div><div class="card"><h3>חזרות מצטברות</h3><div class="fitness-stat">${reps}</div></div></div><div class="card" style="margin-top:18px"><h3>השבוע שלי</h3><div class="weekly-checks">${fitnessWeekHtml()}</div></div><div class="card" style="margin-top:18px"><h3>🏅 ההישגים שלי</h3><div class="achievement-grid">${fitnessAchievementDefs.map(a=>{let got=state.fitness.achievements.includes(a.id);return `<div class="card fit-achievement ${got?'':'locked'}"><div class="emoji">${got?a.icon:'🔒'}</div><h3>${a.name}</h3><small>${a.desc}</small><p class="reward">${got?'הושג ✓':`פרס: ${a.reward} נק׳`}</p></div>`}).join('')}</div></div><div class="card" style="margin-top:18px"><h3>האימונים האחרונים</h3>${logs.length?logs.slice(-8).reverse().map(x=>`<p>✅ ${new Date(x.date+'T12:00:00').toLocaleDateString('he-IL')} · אימון ${x.type} · ${x.minutes} דקות</p>`).join(''):'<p class="empty">לאחר האימון הראשון תופיע כאן ההתקדמות.</p>'}</div>`}
    const renderFitnessPlanBase=renderFitnessPlan;renderFitnessPlan=function(){renderFitnessPlanBase();let grid=$('#fitnessContent .grid');if(grid)grid.insertAdjacentHTML('afterend',fitnessTermsHelp())}
    const forestWordsByAge={
      child:[{word:'CAT',he:'חתול',emoji:'🐱'},{word:'DOG',he:'כלב',emoji:'🐶'},{word:'SUN',he:'שמש',emoji:'☀️'},{word:'BOOK',he:'ספר',emoji:'📘'},{word:'TREE',he:'עץ',emoji:'🌳'},{word:'FISH',he:'דג',emoji:'🐟'},{word:'BALL',he:'כדור',emoji:'⚽'},{word:'APPLE',he:'תפוח',emoji:'🍎'},{word:'HOUSE',he:'בית',emoji:'🏠'},{word:'BIRD',he:'ציפור',emoji:'🐦'}],
      teen:[{word:'FRIEND',he:'חבר',emoji:'🤝'},{word:'SCHOOL',he:'בית ספר',emoji:'🏫'},{word:'MUSIC',he:'מוזיקה',emoji:'🎵'},{word:'FUTURE',he:'עתיד',emoji:'🚀'},{word:'CREATE',he:'ליצור',emoji:'🎨'},{word:'TRAVEL',he:'לטייל',emoji:'✈️'},{word:'HEALTH',he:'בריאות',emoji:'💚'},{word:'LEARN',he:'ללמוד',emoji:'📚'},{word:'CHOOSE',he:'לבחור',emoji:'🎯'},{word:'BRAVE',he:'אמיץ',emoji:'🦁'}],
      adult:[{word:'ACHIEVE',he:'להשיג',emoji:'🏆'},{word:'IMPROVE',he:'לשפר',emoji:'📈'},{word:'DECISION',he:'החלטה',emoji:'🎯'},{word:'KNOWLEDGE',he:'ידע',emoji:'🧠'},{word:'CONFIDENT',he:'בטוח בעצמו',emoji:'💪'},{word:'CHALLENGE',he:'אתגר',emoji:'⛰️'},{word:'PROGRESS',he:'התקדמות',emoji:'🚀'},{word:'PRACTICE',he:'תרגול',emoji:'📝'},{word:'OPPORTUNITY',he:'הזדמנות',emoji:'🚪'},{word:'RESPONSIBLE',he:'אחראי',emoji:'🧭'}]
    };
    function forestTier(){let age=state.profile?.age||'child',stage=state.placement?.stage||0;if(age==='adult'||stage>=4)return'adult';if(age==='teen'||stage>=2)return'teen';return'child'}
    function currentForestWords(){return forestWordsByAge[forestTier()]}
    function forestTierName(){return forestTier()==='adult'?'בוגרים · אוצר מילים מתקדם':forestTier()==='teen'?'נוער · מילים מאתגרות':'ילדים · מילים ראשונות'}
    let forestRound=0,forestStep=0,forestOrder=[];
    function renderGameGate(){let status=$('#gameGateStatus'),button=$('#gameGateButton');if(!status||!button)return;let unlocked=state.appLevel>=4;if(unlocked){status.innerHTML=`<span class="badge">${state.game.world1Done?'הפרק הראשון הושלם ✓':'המשחק פתוח — דרגה 4 הושגה!'}</span>`;button.disabled=false;button.textContent=state.game.world1Done?'לשחק שוב':'כניסה ליער'}else{let need=levelNeed(state.appLevel)-state.levelTasks,levels=4-state.appLevel;status.innerHTML=`<span class="game-lock">🔒 נפתח בדרגה 4</span><p><small>${levels===1?`עוד ${need} משימות לדרגה 4`:`עוד ${levels} דרגות לפתיחת המשחק`}</small></p>`;button.disabled=true;button.textContent='עדיין נעול'}}
    function openLetterForest(){if(state.appLevel<4)return toast('ממשיכים במשימות האנגלית — המשחק נפתח בדרגה 4 🌟');showScreen('game')}
    function startForestAdventure(){forestRound=0;forestStep=0;forestOrder=shuffled(currentForestWords().map((_,i)=>i));renderForestRound()}
    function renderLetterForest(){let box=$('#gameContent');if(!box)return;if(state.appLevel<4){box.innerHTML=`<div class="card empty"><div style="font-size:70px">🔒</div><h2>יער האותיות עדיין נעול</h2><p>השלימו משימות ועלו לדרגה 4 כדי להצטרף לאורי.</p></div>`;return}let done=Math.min(state.game.forestWords.length,currentForestWords().length);box.innerHTML=`<div class="game-world"><div class="game-hud"><span>📖 מילים שהוחזרו: ${done}/${currentForestWords().length}</span><span>⭐ פרס הפרק: 80 נקודות</span></div><img class="uri-game" src="assets/game/uri-front.png" alt="אורי ביער האותיות"><div class="magic-book">📖<br>ספר הקסמים</div><div class="game-panel"><div style="font-size:58px">🌲✨</div><small>עולם 1 · ${forestTierName()}</small><h1>יער האותיות</h1><p>שלום, אני <b>אורי</b>! מילים נגנבו מספר הקסמים והתפזרו ביער. המשימות הותאמו לגיל ולרמת האנגלית שלך. אפשר לעזור לי להחזיר אותן?</p>${state.game.world1Done?'<p class="badge">כבר השלמתם את הפרק — אפשר לשחק שוב!</p>':''}<button class="btn wide" onclick="startForestAdventure()">${state.game.world1Done?'משחק חוזר':'יוצאים להרפתקה!'}</button></div></div>`}
    function forestPositions(n){let spots=[[4,15],[86,15],[4,72],[22,74],[40,75],[58,74],[76,75],[88,71]];return shuffled(spots).slice(0,n)}
    function renderForestRound(){let box=$('#gameContent');if(!box)return;if(forestRound>=forestOrder.length)return finishForestAdventure();let item=currentForestWords()[forestOrder[forestRound]],letters=item.word.split(''),pool=shuffled([...letters,...shuffled('ABCDEFGHIJKLMNOPQRSTUVWXYZ'.split('')).filter(x=>!letters.includes(x)).slice(0,Math.max(2,6-letters.length))]);forestStep=0;box.innerHTML=`<div class="game-world"><div class="game-hud"><span>שלב ${forestRound+1} מתוך ${forestOrder.length}</span><span>📖 ${forestRound}/${currentForestWords().length} מילים הוחזרו</span></div><img class="uri-game" src="assets/game/uri-front.png" alt="אורי"><div class="magic-book">${item.emoji}<br>${item.he}</div><div class="forest-letter-tray">${pool.map(letter=>`<button class="forest-letter" onclick="chooseForestLetter(this,'${letter}')" aria-label="האות ${letter}">${letter}</button>`).join('')}</div><div class="game-panel" style="top:30%"><small>מצאו לפי הסדר את האותיות של:</small><div style="font-size:48px">${item.emoji}</div><h2>${item.he}</h2><button class="speaker" onclick="speak('${item.word.toLowerCase()}')">🔊</button><div class="game-word-slots">${letters.map(()=>'<i></i>').join('')}</div><div class="game-message" id="forestMessage">לחצו על האות הראשונה שמסתתרת ביער</div></div></div>`}
    function chooseForestLetter(button,letter){let item=currentForestWords()[forestOrder[forestRound]],expected=item.word[forestStep],message=$('#forestMessage');if(letter!==expected){button.animate([{transform:'translateX(-5px)'},{transform:'translateX(5px)'},{transform:'translateX(0)'}],{duration:260});message.textContent=`כמעט! חפשו את האות ${expected}`;speak(expected);return}let slots=$$('.game-word-slots i');slots[forestStep].textContent=letter;button.disabled=true;button.style.opacity='.25';forestStep++;if(forestStep<item.word.length){message.textContent=`מצוין! עכשיו חפשו את האות ${item.word[forestStep]}`;speak(letter);return}message.textContent=`כל הכבוד! החזרתם את המילה ${item.word} לספר ✨`;speak(item.word.toLowerCase());if(!state.game.forestWords.includes(item.word))state.game.forestWords.push(item.word);persistState();setTimeout(()=>{forestRound++;renderForestRound()},1200)}
    function finishForestAdventure(){let first=!state.game.rewarded;state.game.world1Done=true;if(first){state.game.rewarded=true;addPoints(80);recordLevelTask();progressWeeklyTask()}persistState();$('#points').textContent=state.points;$('#gameContent').innerHTML=`<div class="card game-complete" style="text-align:center;padding:40px"><div style="font-size:85px">📖✨</div><small>יער האותיות · הפרק הושלם</small><h1>החזרתם את המילים לספר הקסמים!</h1><p>אורי: „איזו עבודה נהדרת! בזכותכם האור חזר ליער.”</p><h2>${first?'קיבלתם 80 נקודות ⭐':'שיחקתם שוב בהצלחה 🌟'}</h2><button class="btn" onclick="startForestAdventure()">לשחק שוב</button> <button class="btn secondary" onclick="showScreen('englishHome')">חזרה לאנגלית</button></div>`;renderGameGate()}
    function installedMode(){return window.matchMedia('(display-mode: standalone)').matches||window.navigator.standalone===true}
    function updateInstallUI(){let btn=$('#installBtn'),textEl=$('#installText');if(!btn||!textEl)return;if(installedMode()){btn.disabled=true;btn.textContent='האפליקציה מותקנת ✓';textEl.textContent='מתקדמים פועלת כאפליקציה מותקנת במכשיר.'}else if(deferredInstallPrompt){btn.disabled=false;btn.textContent='התקנת מתקדמים';textEl.textContent='אפשר להתקין את האפליקציה במסך הבית.'}else{btn.disabled=false;btn.textContent='איך מתקינים?';textEl.textContent='בדפדפן תומך, בחרו בתפריט „התקנת אפליקציה” או „הוספה למסך הבית”.'}}
    async function installApp(){if(installedMode())return toast('האפליקציה כבר מותקנת');if(!deferredInstallPrompt)return toast('פתחו את תפריט הדפדפן ובחרו „התקנת אפליקציה”');deferredInstallPrompt.prompt();await deferredInstallPrompt.userChoice;deferredInstallPrompt=null;updateInstallUI()}
    function startPlacement(){placeIndex=0;placeRight=0;preparePlacementQuestions();$('#placementModal').classList.remove('hidden');renderPlacement()}
    function restartPlacement(){state.placement={pending:true,stage:state.placement?state.placement.stage:0};save()}
    function renderPlacement(){if(!activePlacementQuestions.length)preparePlacementQuestions();let q=activePlacementQuestions[placeIndex];if(!q)return finishPlacement();let percent=Math.round(placeIndex/activePlacementQuestions.length*100);$('#placementContent').innerHTML=`<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px"><b>בדיקת רמה באנגלית</b><button class="close" onclick="cancelPlacement()">×</button></div><div class="progress"><i style="width:${percent}%"></i></div><div style="text-align:center;padding:18px 0"><span class="badge">שאלה ${placeIndex+1} מתוך ${activePlacementQuestions.length}</span><h2>${q.title}</h2><div class="quiz-word">${q.prompt}</div><button class="speaker" onclick="speak('${q.speak}')">🔊</button><div class="answers">${q.answers.map(a=>`<button class="answer" onclick="answerPlacement(this,'${a.replaceAll("'","\\'")}')">${a}</button>`).join('')}</div><button class="btn secondary" style="margin-top:14px" onclick="answerPlacement(null,'__skip')">עדיין לא יודע/ת</button></div>`}
    function cancelPlacement(){$('#placementModal').classList.add('hidden');showScreen('home')}
    function answerPlacement(btn,val){let q=activePlacementQuestions[placeIndex],ok=val===q.correct;if(ok){placeRight++;if(btn)btn.classList.add('correct')}else if(btn)btn.classList.add('wrong');$$('#placementContent .answer').forEach(b=>{b.disabled=true;if(b.textContent===q.correct)b.classList.add('correct')});setTimeout(()=>{placeIndex++;renderPlacement()},650)}
    function finishPlacement(){let stage=placeRight<=2?0:placeRight<=4?1:placeRight<=6?2:placeRight<=8?3:4,starts=[1,15,22,28,60],selected=stages[stage];state.day=Math.max(state.day,starts[stage]);state.completed={letters:stage>0,words:false,quiz:false};state.placement={pending:false,stage,score:placeRight,date:today(),appliedSkip:true};state.profile.level=['zero','basic','starter','growing','advanced'][stage];persistState();$('#placementContent').innerHTML=`<div style="text-align:center;padding:15px"><div style="font-size:65px">${selected.icon}</div><small>מצאנו את נקודת ההתחלה המתאימה</small><h2>${selected.name}</h2><p>${selected.desc}</p><div class="card" style="box-shadow:none;background:#f7f6ff"><b>${placeRight} תשובות נכונות מתוך ${activePlacementQuestions.length}</b><br><small>${stage>0?'החומר שכבר ידוע דולג, ומכאן נלמד דברים חדשים.':'נתחיל בלימוד האותיות והצלילים מהבסיס.'}</small></div><button class="btn wide" style="margin-top:15px" onclick="closePlacement()">למסלול שלי</button></div>`}
    function closePlacement(){$('#placementModal').classList.add('hidden');renderAll();toast('המסלול האישי שלך מוכן 🚀')}
    $$('#ageChoices .choice').forEach(b=>b.onclick=()=>{$$('#ageChoices .choice').forEach(x=>x.classList.remove('selected'));b.classList.add('selected');selectedAge=b.dataset.age});
    $('#profileBtn').onclick=()=>showScreen('settings');$('#closeAvatar').onclick=()=>$('#avatarModal').classList.add('hidden');$('#avatarModal').onclick=e=>{if(e.target===$('#avatarModal'))$('#avatarModal').classList.add('hidden')};
    $('#avatarFile').onchange=e=>{let file=e.target.files[0];if(!file)return;if(!file.type.startsWith('image/'))return toast('אפשר לבחור קובץ תמונה בלבד');let reader=new FileReader();reader.onload=ev=>{let img=new Image();img.onload=()=>{let size=Math.min(img.width,img.height),canvas=document.createElement('canvas');canvas.width=canvas.height=240;let ctx=canvas.getContext('2d');ctx.drawImage(img,(img.width-size)/2,(img.height-size)/2,size,size,0,0,240,240);let a={type:'image',value:canvas.toDataURL('image/jpeg',.78)};if(avatarTarget==='onboard'){selectedAvatar=a;renderAvatarChoices('onboardAvatars')}else{state.profile.avatar=a;save();renderAvatarChoices('profileAvatars');toast('התמונה נשמרה במכשיר 📷')}};img.onerror=()=>toast('לא הצלחנו לקרוא את התמונה');img.src=ev.target.result};reader.readAsDataURL(file);e.target.value=''};
    $('#startBtn').onclick=()=>{let name=$('#nameInput').value.trim();if(!name)return toast('כדאי לכתוב שם כדי שנוכל להכיר');let domains=selectedStartDomain==='both'?['english','fitness']:[selectedStartDomain],chosenLevel=$('#levelInput').value,initialStage={zero:0,basic:1,starter:2,advanced:4}[chosenLevel]||0;state.profile={name,age:selectedAge,level:chosenLevel,time:$('#timeInput').value,avatar:selectedAvatar,domains};state.appLevel=1;state.levelTasks=0;state.placement={pending:domains.includes('english'),stage:initialStage,chosenStage:initialStage};state.lastOpen=today();save();showScreen(selectedStartDomain==='fitness'?'fitness':selectedStartDomain==='both'?'home':'englishHome')};
    window.addEventListener('beforeinstallprompt',e=>{e.preventDefault();deferredInstallPrompt=e;updateInstallUI()});window.addEventListener('appinstalled',()=>{deferredInstallPrompt=null;updateInstallUI();toast('מתקדמים הותקנה בהצלחה 🎉')});window.addEventListener('pageshow',e=>{if(e.persisted)openMainScreen()});if('serviceWorker'in navigator&&location.protocol.startsWith('http'))window.addEventListener('load',()=>navigator.serviceWorker.register('./sw.js').catch(()=>{}));
    checkDay();renderAll();initShabbat();openMainScreen();
  

(function(){
  function overallRankData(){
    const englishTasks=Number(state.levelTasks)||0;
    const fitnessUnits=Math.floor((Number(state.fitness?.points)||0)/40);
    const total=englishTasks+fitnessUnits;
    const names=['מתחיל','מתקדם','מתמיד','אלוף','מאסטר','אגדה'];
    const thresholds=[0,8,18,32,50,75];
    let level=1;
    for(let i=1;i<thresholds.length;i++) if(total>=thresholds[i]) level=i+1;
    const current=thresholds[level-1], next=thresholds[level]??current;
    const pct=level===thresholds.length?100:Math.max(0,Math.min(100,Math.round((total-current)/(next-current)*100)));
    return {level,name:names[level-1],total,next,pct};
  }
  const oldRenderHomeRanks=window.renderHomeRanks;
  window.renderHomeRanks=function(){
    const domains=state.profile?.domains||[];
    if(domains.includes('english')&&domains.includes('fitness')){
      const box=document.querySelector('#homeRankArea'); if(!box)return;
      const r=overallRankData();
      box.innerHTML=`<div class="card general-rank-card"><div class="general-rank-head"><div><small>הדרגה הכללית שלי</small><h2>דרגה ${r.level} · ${r.name}</h2></div><div class="general-rank-icon">🚀</div></div><div class="progress"><i style="width:${r.pct}%"></i></div><div class="general-rank-meta"><span>אנגלית וכושר יחד</span><span>${r.level===6?'הגעת לדרגה הגבוהה ביותר':`${r.total} מתוך ${r.next} צעדי התקדמות`}</span></div></div>`;
      return;
    }
    oldRenderHomeRanks();
  };

  const oldRenderFitness=window.renderFitness;
  window.renderFitness=function(){
    oldRenderFitness();
    const box=document.querySelector('#fitnessContent');
    if(!box||!state.fitness?.configured||state.fitness?.limitations)return;
    if(!box.querySelector('.fitness-week-main')){
      const timer=box.querySelector('.quick-timer-card');
      const html=`<div class="fitness-week-main">${weekStatusHTML('fitness')}</div>`;
      if(timer) timer.insertAdjacentHTML('beforebegin',html); else box.insertAdjacentHTML('beforeend',html);
    }
  };

  const oldFinishFitnessWorkout=window.finishFitnessWorkout;
  window.finishFitnessWorkout=function(){
    oldFinishFitnessWorkout();
    setTimeout(()=>{ if(document.querySelector('#fitness.screen.active')) window.renderFitness(); },30);
  };

  const oldComplete=window.complete;
  window.complete=function(type,n){
    oldComplete(type,n);
    if(state.completed?.letters&&state.completed?.words&&state.completed?.quiz){
      state.studyDays=state.studyDays||{};
      state.studyDays[today()]=true;
      save();
    }
  };

  const oldRenderAll=window.renderAll;
  window.renderAll=function(){ oldRenderAll(); window.renderHomeRanks(); };
})();


